INSERT INTO news (slug, date_label, tag, title, text, content, image, published, images)
VALUES (
  'sezon-2026-semena-ovoshchey-optom-dlya-roznichnoy-torgovli',
  '26 апреля 2026',
  'Сезон 2026',
  'Сезон 2026: какие семена овощей закупить оптом для розничной торговли',
  'Разбираем, какие сорта и культуры стоит включить в оптовый заказ к новому сезону, чтобы магазин уверенно отработал весенний пик спроса.',
  'Сезон 2026 уже стартовал, и розничным магазинам сейчас особенно важно правильно сформировать ассортимент семян овощей оптом. От выбора сортов в феврале — марте напрямую зависит, насколько уверенно полки будут продаваться весной.\n\nВ Иваново и Ивановской области спрос традиционно концентрируется вокруг базовых культур: огурцы, томаты, морковь, свёкла, лук, капуста, перец и зелень. По нашему опыту работы с розничными магазинами и фермерскими хозяйствами, на эти позиции приходится до 70% весенних продаж семян.\n\nЧто стоит закупать оптом в первую очередь:\n— Огурцы: партенокарпические гибриды для теплиц и универсальные пчёлоопыляемые сорта для открытого грунта.\n— Томаты: ранние и среднеспелые сорта для салата и засолки, обязательно несколько крупноплодных.\n— Морковь: лежкие сорта типа Шантанэ и Нантская — это безусловный хит для хранения и продажи.\n— Капуста: ранняя белокочанная, среднепоздняя для квашения, цветная и брокколи в небольших объёмах.\n— Зелень: укроп, петрушка, салат, базилик — быстрая оборачиваемость и стабильный спрос.\n\nЦветочные культуры и газонные травы добавят к среднему чеку и помогут отстроиться от соседей. По цветам в розницу хорошо идут однолетники: бархатцы, петуния, циния, настурция. По газонной траве — универсальные смеси под климат средней полосы.\n\nКупить семена оптом для розничной торговли в нашей компании можно с прямой доставкой по городу Иваново и области. Все семена напрямую от селекционных станций, всхожесть 97%, ассортимент 560+ позиций. Прайс на семена оптом высылаем по запросу — звоните или оставляйте заявку на сайте.',
  'https://cdn.poehali.dev/projects/6e30ca34-8fe1-4535-8d16-622fe38c58fb/files/78531f9b-529f-4a54-a13d-6590992b45d3.jpg',
  TRUE,
  '[]'::jsonb
);